import{c as i,Z as l,Q as e,j as o,o as s,m as r}from"./chunks/framework.qjzPVSkb.js";const g=JSON.parse('{"title":"Stable Diffusion","description":"开源 AI 图像生成模型——本地运行，高度定制，ControlNet + LoRA 生态丰富","frontmatter":{"title":"Stable Diffusion","description":"开源 AI 图像生成模型——本地运行，高度定制，ControlNet + LoRA 生态丰富","difficulty":"beginner"},"headers":[],"relativePath":"tools/stable-diffusion.md","filePath":"tools/stable-diffusion.md"}'),n={name:"tools/stable-diffusion.md"};function h(d,t,p,u,b,c){const a=l("DifficultyBadge");return e(),o("div",null,[s(a,{level:"beginner"}),t[0]||(t[0]=r(`<h1 id="stable-diffusion" tabindex="-1">Stable Diffusion <a class="header-anchor" href="#stable-diffusion" aria-label="Permalink to &quot;Stable Diffusion&quot;">​</a></h1><h2 id="一句话定位" tabindex="-1">一句话定位 <a class="header-anchor" href="#一句话定位" aria-label="Permalink to &quot;一句话定位&quot;">​</a></h2><p><strong>开源图像生成模型</strong>——免费、本地运行、高度可定制。如果说 Midjourney 是法拉利，Stable Diffusion 就是可以自己改装的超级跑车。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th>项目</th><th>详情</th></tr></thead><tbody><tr><td>公司</td><td>Stability AI + 开源社区</td></tr><tr><td>价格</td><td>免费（开源）</td></tr><tr><td>主要模型</td><td>SDXL / SD 3 / SD 3.5</td></tr><tr><td>平台</td><td>Windows / macOS / Linux</td></tr><tr><td>首发时间</td><td>2022 年 8 月</td></tr></tbody></table><h2 id="核心功能" tabindex="-1">核心功能 <a class="header-anchor" href="#核心功能" aria-label="Permalink to &quot;核心功能&quot;">​</a></h2><h3 id="🖥️-本地运行" tabindex="-1">🖥️ 本地运行 <a class="header-anchor" href="#🖥️-本地运行" aria-label="Permalink to &quot;🖥️ 本地运行&quot;">​</a></h3><p>在自己的电脑上直接运行（需要独立显卡，推荐 6GB+ VRAM）。不需要联网，不需要付费，图像完全私有。</p><h3 id="🔧-controlnet" tabindex="-1">🔧 ControlNet <a class="header-anchor" href="#🔧-controlnet" aria-label="Permalink to &quot;🔧 ControlNet&quot;">​</a></h3><p>这是 SD 生态中最强大的工具之一——可以精确控制图像生成的方向：</p><ul><li><strong>Canny（边缘检测）</strong>：上传草图，按轮廓生成</li><li><strong>Pose（姿态）</strong>：指定人物的姿势和动作</li><li><strong>Depth（深度）</strong>：控制空间深度关系</li><li><strong>Scribble（涂鸦）</strong>：随手画画变成完整图像</li><li><strong>IP-Adapter</strong>：参考另一张图的风格</li></ul><h3 id="🎨-lora-模型" tabindex="-1">🎨 LoRA 模型 <a class="header-anchor" href="#🎨-lora-模型" aria-label="Permalink to &quot;🎨 LoRA 模型&quot;">​</a></h3><p>社区训练的大量风格化小模型：</p><ul><li>特定人物 LoRA（某个明星或角色）</li><li>特定风格 LoRA（水墨画、像素风、赛博朋克）</li><li>特定物品 LoRA（某种建筑、某种服装）</li></ul><p>只需下载几百 MB 的 LoRA 文件，就能让 SD 学会新风格。</p><h3 id="🌐-webui" tabindex="-1">🌐 WebUI <a class="header-anchor" href="#🌐-webui" aria-label="Permalink to &quot;🌐 WebUI&quot;">​</a></h3><p>最流行的使用界面是 <a href="https://github.com/AUTOMATIC1111/stable-diffusion-webui" target="_blank" rel="noreferrer">Automatic1111 WebUI</a> 和 <a href="https://github.com/comfyanonymous/ComfyUI" target="_blank" rel="noreferrer">ComfyUI</a>（节点式工作流）。</p><h2 id="优势" tabindex="-1">优势 <a class="header-anchor" href="#优势" aria-label="Permalink to &quot;优势&quot;">​</a></h2><ul><li><strong>完全免费</strong>：开源，不需要付费订阅</li><li><strong>可本地运行</strong>：数据不出你的电脑，隐私有保障</li><li><strong>高度可定制</strong>：ControlNet、LoRA、插件生态极其丰富</li><li><strong>社区庞大</strong>：全球最大的 AI 图像生成开源社区</li><li><strong>图生图强</strong>：可以上传参考图进行精确控制</li></ul><h2 id="不足" tabindex="-1">不足 <a class="header-anchor" href="#不足" aria-label="Permalink to &quot;不足&quot;">​</a></h2><ul><li>上手门槛高：需要安装 Python、CUDA、下载模型等</li><li>依赖硬件：需要独立显卡，显存不够可能无法运行</li><li>默认效果不如 Midjourney（需要自己调参数和模型）</li><li>需要学习成本：WebUI 功能多但复杂</li><li>对非法内容的过滤不如商业产品严格（需要自律）</li></ul><h2 id="适合谁" tabindex="-1">适合谁？ <a class="header-anchor" href="#适合谁" aria-label="Permalink to &quot;适合谁？&quot;">​</a></h2><ul><li>✅ 预算有限的创作者</li><li>✅ 喜欢 DIY、愿意折腾的技术爱好者</li><li>✅ 需要精确控制图像生成的场景（ControlNet）</li><li>✅ 对数据隐私有要求的用户</li><li>✅ 想学习 AI 图像生成原理的开发者</li><li>⚠️ 追求开箱即用的用户 → 选 Midjourney 或 DALL·E</li></ul><h2 id="快速上手" tabindex="-1">快速上手 <a class="header-anchor" href="#快速上手" aria-label="Permalink to &quot;快速上手&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 使用 ComfyUI（推荐新手用 Stability Matrix 一键安装）</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/comfyanonymous/ComfyUI.git</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ComfyUI</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pip</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -r</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> requirements.txt</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> main.py</span></span></code></pre></div><p>或者使用 <a href="https://github.com/LykosAI/StabilityMatrix" target="_blank" rel="noreferrer">Stability Matrix</a>（图形化启动器），一键管理 SD WebUI、ComfyUI 和模型。</p><h2 id="常用资源" tabindex="-1">常用资源 <a class="header-anchor" href="#常用资源" aria-label="Permalink to &quot;常用资源&quot;">​</a></h2><ul><li><strong>模型下载</strong>：<a href="https://civitai.com" target="_blank" rel="noreferrer">CivitAI</a> —— 最大的 SD 模型社区</li><li><strong>LoRA 下载</strong>：CivitAI 上有海量 LoRA</li><li><strong>教程</strong>：B 站搜索 &quot;Stable Diffusion 教程&quot;</li><li><strong>提示词参考</strong>：CivitAI 上每张图片都附带完整 Prompt</li></ul><h2 id="关联阅读" tabindex="-1">关联阅读 <a class="header-anchor" href="#关联阅读" aria-label="Permalink to &quot;关联阅读&quot;">​</a></h2><ul><li><a href="/ai-knowledge/tools/midjourney.html">Midjourney</a> —— 商业图像生成对比</li><li><a href="/ai-knowledge/tools/dalle.html">DALL·E</a> —— OpenAI 的图像生成方案</li><li><a href="/ai-knowledge/prompts/what-is-prompt.html">什么是 Prompt</a> —— 好的 Prompt 对图像生成至关重要</li></ul>`,30))])}const k=i(n,[["render",h]]);export{g as __pageData,k as default};
